const src = $json.body || $json || {};
if (!src.spreadsheetId) throw new Error('Missing spreadsheetId');
if (!src.driveRootFolderId) throw new Error('Missing driveRootFolderId');
if (!src.inputFolderId) throw new Error('Missing inputFolderId');
const stamp = new Date().toISOString().replace(/[-:.TZ]/g,'').slice(0,14);
const rand = Math.random().toString(36).slice(2,8);
const jobId = `job_${stamp}_${rand}`;
return [{json:{spreadsheetId:src.spreadsheetId,driveRootFolderId:src.driveRootFolderId,inputFolderId:src.inputFolderId,jobId,jobName:src.jobName || jobId,sourceType:'drive_folder_images',basePrompt:src.basePrompt || 'Create an improved professional presentation slide image inspired by the source slide. Keep the slide core message, improve readability, visual hierarchy, and polish. Return a single high-quality slide-like image.',timeoutMs:Number(src.timeoutMs || 120000),waitSeconds:Number(src.waitSeconds || 2),model:'gpt-image-2',baseUrl:'https://api.wisgate.ai/v1'}}];

const base = $node['Code - Init Run'].json;
const files = $json.files || [];
if (!files.length) throw new Error('No image files found in inputFolderId');
return files.map((f, idx) => { const i=idx+1; const p=String(i).padStart(3,'0'); return {json:{...base,slideIndex:i,slideKey:`${base.jobId}_slide_${p}`,originalFileName:f.name,originalDriveFileId:f.id,originalDriveUrl:f.webViewLink || `https://drive.google.com/file/d/${f.id}/view`,jobOutputFolderId:$node['Drive - Create Output Folder'].json.id,outputFileName:`slide_${p}.png`,status:'pending',attempt:0,prompt:`${base.basePrompt}
Slide index: ${i}. Source file name: ${f.name}.`}}; });

const source = $node['Loop Slides'].json;
const resp = $json;
const b64 = resp.data?.[0]?.b64_json;
if (b64) { return [{json:{...source,status:'success',attempt:Number(source.attempt||0)+1,errorType:'',errorMessage:'',finishedAt:new Date().toISOString()},binary:{outputImage:{data:b64,mimeType:'image/png',fileName:source.outputFileName}}}]; }
const text = JSON.stringify(resp.error || resp.message || resp).slice(0,3000) || 'Unknown error';
const lower = text.toLowerCase();
const status = lower.includes('timeout') ? 'timeout' : 'failed';
const errorType = status === 'timeout' ? 'TIMEOUT_120S' : 'API_ERROR';
return [{json:{...source,status,errorType,errorMessage:text,attempt:Number(source.attempt||0)+1,finishedAt:new Date().toISOString()}}];

const job = $node['Code - Init Run'].json;
const rows = $input.all().map(i => i.json).filter(r => r.jobId === job.jobId);
const totalSlides = rows.length;
const successSlides = rows.filter(r => r.status === 'success').length;
const failedSlides = rows.filter(r => r.status === 'failed').length;
const timeoutSlides = rows.filter(r => r.status === 'timeout').length;
const status = (failedSlides || timeoutSlides) ? 'completed_with_errors' : 'done';
const outputFolderId = $node['Drive - Create Output Folder'].json.id;
return [{json:{...job,status,totalSlides,successSlides,failedSlides,timeoutSlides,outputFolderId,outputFolderLink:`https://drive.google.com/drive/folders/${outputFolderId}`}}];
